const alert = $input.first().json;
const alertStatus = alert.status || 'firing';
const now = new Date();
const fiveMinAgo = new Date(now.getTime() - 5 * 60 * 1000);
const startNano = (fiveMinAgo.getTime() * 1_000_000).toString();
const endNano = (now.getTime() * 1_000_000).toString();
function toKst(d) {
  const k = new Date(d.getTime() + 9 * 3600 * 1000);
  return `${k.getUTCFullYear()}-${String(k.getUTCMonth()+1).padStart(2,'0')}-${String(k.getUTCDate()).padStart(2,'0')} ${String(k.getUTCHours()).padStart(2,'0')}:${String(k.getUTCMinutes()).padStart(2,'0')}`;
}
const timeRangeKst = `${toKst(fiveMinAgo)} ~ ${toKst(now)} (KST)`;
return [{ json: { alertStatus, startNano, endNano, timeRangeKst } }];

const lokiResponse = $input.first().json;
const alertInfo = $('Parse Alert').first().json;

const tagChannelMap = {
  RAG_REINDEX:        '#ai-alert',
  PAYMENT_ESCALATION: '#business-insight',
  CARD_SYNC:          '#backend',
  ES_MIGRATION:       '#backend',
  DEFAULT:            '#error-alert',
};

const fmt = '\n\n출력 형식 — Slack mrkdwn 규칙:\n- 굵게는 *텍스트* (별표 1개, **텍스트** 금지)\n- 인라인 코드는 `코드`\n- 헤더(#) 사용 금지, 가로 구분선(---) 사용 금지\n- 리스트는 • 으로 시작 (-, * 금지)\n- 한국어로 작성, :mag: 외 이모지 자제, 간결하게';

const sysPrompts = {
  RAG_REINDEX:        '당신은 POCAT AI RAG 재색인 작업 리포터입니다. 로그를 분석하여 3섹션(:mag: 헤더)으로 정리하세요.\n:mag: *1. 작업 요약* • 시작/완료 시각/처리 건수/성공-실패 비율\n:mag: *2. 상태 분석* • 정상 완료인지 부분 실패인지 판단\n:mag: *3. 후속 조치* • 실패 건수가 있을 경우 권장 조치, 정상이면 "정상 완료" 한 줄' + fmt,
  PAYMENT_ESCALATION: '당신은 POCAT 결제 승격 플로우 리포터입니다. 로그를 분석하여 3섹션(:mag: 헤더)으로 정리하세요.\n:mag: *1. 플로우 요약* • 처리된 승격 건수/스킵 건수/완료 시각\n:mag: *2. 상태 분석* • 정상 처리인지 이슈가 있는지 판단\n:mag: *3. 후속 조치* • 이상 없으면 "정상 처리" 한 줄, 이슈 있으면 구체적 조치' + fmt,
  CARD_SYNC:          '당신은 POCAT 카드 동기화 작업 리포터입니다. 로그를 분석하여 3섹션(:mag: 헤더)으로 정리하세요.\n:mag: *1. 동기화 요약* • 완료 시각/신규 카드 수/처리 세트\n:mag: *2. 상태 분석* • 정상 완료인지 부분 실패인지 판단\n:mag: *3. 후속 조치* • 정상이면 "정상 완료" 한 줄, 이슈 있으면 구체적 조치' + fmt,
  ES_MIGRATION:       '당신은 POCAT ES 마이그레이션 작업 리포터입니다. 로그를 분석하여 3섹션(:mag: 헤더)으로 정리하세요.\n:mag: *1. 마이그레이션 요약* • 완료 시각/색인 건수/소요 시간\n:mag: *2. 상태 분석* • 정상 완료인지 판단\n:mag: *3. 후속 조치* • 정상이면 "정상 완료" 한 줄, 이슈 있으면 구체적 조치' + fmt,
  DEFAULT:            '당신은 POCAT 운영 이벤트 리포터입니다. 로그를 분석하여 3섹션(:mag: 헤더)으로 정리하세요.\n:mag: *1. 이벤트 요약* • 발생 시각/이벤트 유형/처리 결과\n:mag: *2. 상태 분석* • 정상 여부 판단\n:mag: *3. 후속 조치* • 필요 시 조치, 정상이면 "정상" 한 줄' + fmt,
};

let allLines = [];
if (lokiResponse.data && lokiResponse.data.result) {
  for (const stream of lokiResponse.data.result) {
    if (stream.values) {
      for (const [, line] of stream.values) allLines.push(line);
    }
  }
}

const tagGroups = {};
for (const line of allLines) {
  const match = line.match(/\[([A-Z_]+)\]/);
  const tag = (match && tagChannelMap[match[1]] !== undefined) ? match[1] : 'DEFAULT';
  if (!tagGroups[tag]) tagGroups[tag] = [];
  tagGroups[tag].push(line);
}

const maxChars = 5000;
return Object.entries(tagGroups).map(([tag, lines]) => {
  let logs = lines.join('\n---\n');
  if (logs.length > maxChars) logs = logs.substring(0, maxChars) + '\n... (truncated)';
  return { json: {
    tag,
    logCount: lines.length,
    channelName: tagChannelMap[tag] || tagChannelMap.DEFAULT,
    systemPrompt: sysPrompts[tag] || sysPrompts.DEFAULT,
    userPrompt: `[${tag}] 이벤트\n[Time Range] ${alertInfo.timeRangeKst}\n[Log Count] ${lines.length}건\n\n--- 로그 ---\n${logs}`,
    alertInfo,
  }};
});

const aiOutput = $input.first().json;
const original = $('Group by Tag').item.json;
let analysis = aiOutput.output || aiOutput.text || '분석 실패';
analysis = analysis
  .replace(/\*\*(.+?)\*\*/g, '*$1*')
  .replace(/^\s*#+\s+/gm, '')
  .replace(/^\s*-{3,}\s*$/gm, '')
  .replace(/\n{3,}/g, '\n\n');
const text = `:information_source: *[${original.tag}] INFO 이벤트*\n\n*Time:* ${original.alertInfo.timeRangeKst}\n*Log Count:* ${original.logCount}건\n\n${analysis}`;
return [{ json: { text, channelName: original.channelName } }];
